namespace sv_f65c8ab83f3d43b8a616667300884212.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@using sv_f65c8ab83f3d43b8a616667300884212.Services
@inject IChatService ChatService
@inject IJSRuntime JS
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ── Left sidebar: channel list ── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @foreach (var channel in channels)
            {
                <li class="channel-item @(channel.Id == activeChannelId ? "active" : "")"
                    @onclick="() => SelectChannelAsync(channel)">
                    <div class="channel-name"># @channel.Name</div>
                    <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </li>
            }
        </ul>
    </aside>

    @* ── Main message area ── *@
    <section class="message-area @(threadRootMessage is null ? "full-width" : "")">
        @if (activeChannel is not null)
        {
            <div class="message-header">
                <h2># @activeChannel.Name</h2>
                <p>@activeChannel.Description</p>
            </div>

            <div class="message-list" @ref="messageListRef" @onscroll="OnMessageListScroll">
                @if (isLoadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @foreach (var msg in messages)
                {
                    <div class="message-row" @key="msg.Id">
                        <div class="message-content-wrap">
                            <div class="message-meta">
                                <span class="author">@msg.Author</span>
                                <span class="timestamp">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="message-text">@msg.Content</div>

                            @if (msg.Reactions.Count > 0)
                            {
                                <div class="reactions-row">
                                    @foreach (var r in msg.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => ReactAsync(msg.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @{ var threadInfo = threadSummaries.GetValueOrDefault(msg.Id); }
                            @if (threadInfo is not null)
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                    @threadInfo.ReplyCount @(threadInfo.ReplyCount == 1 ? "reply" : "replies")
                                </button>
                            }
                        </div>

                        <div class="message-actions">
                            <button class="action-btn" title="Reply" @onclick="() => OpenThreadAsync(msg)">💬</button>
                            <button class="action-btn" title="React" @onclick="() => ToggleEmojiPicker(msg.Id)">😀</button>
                        </div>

                        @if (emojiPickerMessageId == msg.Id)
                        {
                            <div class="emoji-picker">
                                @foreach (var emoji in commonEmojis)
                                {
                                    <button class="emoji-option" @onclick="() => ReactAsync(msg.Id, emoji)">@emoji</button>
                                }
                            </div>
                        }
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="newMessageText" @bind:event="oninput" placeholder="Type a message…"
                          @onkeydown="OnMessageKeyDown" rows="2"></textarea>
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(newMessageText)">Send</button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ── Right panel: thread view ── *@
    @if (threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-btn" @onclick="CloseThread">✕</button>
            </div>

            <div class="thread-root-quote">
                <span class="author">@threadRootMessage.Author</span>
                <p>@threadRootMessage.Content</p>
            </div>

            <div class="thread-replies">
                @foreach (var reply in threadReplies)
                {
                    <div class="message-row thread-reply" @key="reply.Id">
                        <div class="message-content-wrap">
                            <div class="message-meta">
                                <span class="author">@reply.Author</span>
                                <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-text">@reply.Content</div>

                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reactions-row">
                                    @foreach (var r in reply.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => ReactAsync(reply.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="replyText" @bind:event="oninput" placeholder="Reply…"
                          @onkeydown="OnReplyKeyDown" rows="2"></textarea>
                <button class="send-btn" @onclick="SendReplyAsync" disabled="@string.IsNullOrWhiteSpace(replyText)">Reply</button>
            </div>
        </aside>
    }
</div>

@code {
    private List<Channel> channels = new();
    private List<Message> messages = new();
    private List<Message> threadReplies = new();
    private Dictionary<int, ThreadSummary> threadSummaries = new();

    private Channel? activeChannel;
    private int activeChannelId;
    private Message? threadRootMessage;

    private string newMessageText = "";
    private string replyText = "";
    private int? emojiPickerMessageId;

    private bool isLoadingMore;
    private bool hasMoreMessages = true;
    private const int PageSize = 30;

    private ElementReference messageListRef;

    private static readonly string[] commonEmojis = { "👍", "❤️", "😂", "🎉", "🔥", "👀" };

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannelAsync(channels[0]);
        }
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        activeChannel = channel;
        activeChannelId = channel.Id;
        messages.Clear();
        threadSummaries.Clear();
        hasMoreMessages = true;
        emojiPickerMessageId = null;

        CloseThread();

        var loaded = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        messages = loaded;
        hasMoreMessages = loaded.Count == PageSize;

        await BuildThreadSummaries();
        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh channel list to update unread counts
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (isLoadingMore || !hasMoreMessages) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannelId, messages.Count, PageSize);
        hasMoreMessages = older.Count == PageSize;

        // Prepend older messages
        messages.InsertRange(0, older);
        await BuildThreadSummaries();

        isLoadingMore = false;
    }

    private async Task OnMessageListScroll()
    {
        // JS interop to check if scrolled to top
        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 1)
        {
            await LoadOlderMessagesAsync();
        }
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageText) || activeChannel is null) return;

        var sent = await ChatService.SendMessageAsync(activeChannelId, newMessageText.Trim(), null);
        messages.Add(sent);
        newMessageText = "";
    }

    private async Task OnMessageKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    private async Task OpenThreadAsync(Message rootMessage)
    {
        threadRootMessage = rootMessage;
        emojiPickerMessageId = null;
        threadReplies = await ChatService.GetThreadAsync(rootMessage.Id);
    }

    private void CloseThread()
    {
        threadRootMessage = null;
        threadReplies.Clear();
        replyText = "";
    }

    private async Task SendReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(replyText) || threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannelId, replyText.Trim(), threadRootMessage.Id);
        threadReplies.Add(reply);
        replyText = "";

        // Update thread summary
        threadSummaries[threadRootMessage.Id] = new ThreadSummary(
            threadRootMessage.Id,
            threadReplies.Count,
            reply.SentAt
        );
    }

    private async Task OnReplyKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendReplyAsync();
        }
    }

    private async Task ReactAsync(int messageId, string emoji)
    {
        emojiPickerMessageId = null;
        await ChatService.AddReactionAsync(messageId, emoji);

        // Refresh messages to show updated reactions
        if (activeChannel is not null)
        {
            var refreshed = await ChatService.GetMessagesAsync(activeChannelId, 0, messages.Count);
            messages = refreshed;
        }

        // Refresh thread replies if thread is open
        if (threadRootMessage is not null)
        {
            threadReplies = await ChatService.GetThreadAsync(threadRootMessage.Id);
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task BuildThreadSummaries()
    {
        // Identify messages that have replies (messages referencing them via ReplyToId)
        var rootIds = messages
            .Where(m => m.ReplyToId is null)
            .Select(m => m.Id)
            .ToHashSet();

        var repliesByRoot = messages
            .Where(m => m.ReplyToId is not null && rootIds.Contains(m.ReplyToId.Value))
            .GroupBy(m => m.ReplyToId!.Value);

        foreach (var group in repliesByRoot)
        {
            threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt)
            );
        }

        // Also fetch thread info for messages that might have replies outside current page
        foreach (var msg in messages.Where(m => m.ReplyToId is null && !threadSummaries.ContainsKey(m.Id)))
        {
            try
            {
                var thread = await ChatService.GetThreadAsync(msg.Id);
                if (thread.Count > 0)
                {
                    threadSummaries[msg.Id] = new ThreadSummary(msg.Id, thread.Count, thread.Max(t => t.SentAt));
                }
            }
            catch
            {
                // Thread may not exist; ignore
            }
        }
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string TruncateDescription(string description)
    {
        return description.Length > 40 ? description[..37] + "…" : description;
    }
}

