+.no-channel-selected {
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    height: 100%;
+    color: #717274;
+    font-size: 1.1rem;
+}
+
+/* ── Thread panel ── */
+.thread-panel {
+    width: 25%;
+    min-width: 260px;
+    background: #19171d;
+    display: flex;
+    flex-direction: column;
+    overflow: hidden;
+}
+
+.thread-header {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    padding: 12px 16px;
+    border-bottom: 1px solid #2c2d30;
+    flex-shrink: 0;
+}
+
+.thread-header h3 {
+    margin: 0;
+    font-size: 1rem;
+    font-weight: 700;
+    color: #fff;
+}
+
+.close-btn {
+    background: none;
+    border: none;
+    color: #9ea0a5;
+    font-size: 1.2rem;
+    cursor: pointer;
+    padding: 2px 6px;
+    border-radius: 4px;
+    line-height: 1;
+}
+
+.close-btn:hover {
+    background: #2c2d30;
+    color: #fff;
+}
+
+.thread-root-quote {
+    padding: 12px 16px;
+    border-bottom: 1px solid #2c2d30;
+    background: #222529;
+    flex-shrink: 0;
+}
+
+.thread-root-quote .author {
+    font-size: 0.85rem;
+}
+
+.thread-root-quote p {
+    margin: 4px 0 0;
+    font-size: 0.85rem;
+    color: #d1d2d3;
+    line-height: 1.4;
+}
+
+.thread-replies {
+    flex: 1;
+    overflow-y: auto;
+    padding: 8px 0;
+}
+
+.thread-reply {
+    padding: 6px 16px;
+}
+
+.thread-reply .message-content-wrap {
+    padding-right: 0;
+}
+
+/* ── Scrollbar styling ── */
+.message-list::-webkit-scrollbar,
+.thread-replies::-webkit-scrollbar,
+.channel-list::-webkit-scrollbar {
+    width: 6px;
+}
+
+.message-list::-webkit-scrollbar-thumb,
+.thread-replies::-webkit-scrollbar-thumb,
+.channel-list::-webkit-scrollbar-thumb {
+    background: #3c3f43;
+    border-radius: 3px;
+}
+
+.message-list::-webkit-scrollbar-track,
+.thread-replies::-webkit-scrollbar-track,
+.channel-list::-webkit-scrollbar-track {
+    background: transparent;
+}
+

